--
-- Table structure for table `employees`
--

DROP TABLE IF EXISTS `employees`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `employees` (
  `emp_id` int NOT NULL AUTO_INCREMENT COMMENT '员工ID',
  `emp_no` varchar(32) NOT NULL COMMENT '员工工号',
  `name` varchar(64) NOT NULL COMMENT '员工姓名',
  `gender` tinyint DEFAULT '1' COMMENT '性别：1-男 2-女',
  `department` varchar(64) NOT NULL COMMENT '所属部门',
  `position` varchar(64) NOT NULL COMMENT '岗位名称',
  `job_level` varchar(32) DEFAULT NULL COMMENT '职级',
  `hire_date` date NOT NULL COMMENT '入职日期',
  `regular_date` date DEFAULT NULL COMMENT '转正日期',
  `resign_date` date DEFAULT NULL COMMENT '离职日期',
  `phone` varchar(20) DEFAULT NULL COMMENT '手机号码',
  `email` varchar(128) DEFAULT NULL COMMENT '企业邮箱',
  `id_card` varchar(18) DEFAULT NULL COMMENT '身份证号',
  `manager_id` int DEFAULT NULL COMMENT '直属领导ID',
  `emp_status` tinyint NOT NULL DEFAULT '1' COMMENT '员工状态：1-试用期 2-在职 3-离职',
  `annual_leave_quota` decimal(4,1) DEFAULT '5.0' COMMENT '年度年假总天数',
  `annual_leave_used` decimal(4,1) DEFAULT '0.0' COMMENT '已休年假天数',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`emp_id`),
  UNIQUE KEY `emp_no` (`emp_no`),
  UNIQUE KEY `phone` (`phone`),
  UNIQUE KEY `email` (`email`),
  KEY `manager_id` (`manager_id`),
  CONSTRAINT `employees_ibfk_1` FOREIGN KEY (`manager_id`) REFERENCES `employees` (`emp_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='员工主表';
/*!40101 SET character_set_client = @saved_cs_client */;

