DROP TABLE IF EXISTS `leave_requests`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `leave_requests` (
  `leave_id` int NOT NULL AUTO_INCREMENT COMMENT '请假申请ID',
  `emp_id` int NOT NULL COMMENT '员工ID',
  `leave_type` tinyint NOT NULL COMMENT '请假类型：1-年假 2-事假 3-病假 4-婚假 5-产假 6-丧假',
  `start_time` datetime NOT NULL COMMENT '请假开始时间',
  `end_time` datetime NOT NULL COMMENT '请假结束时间',
  `leave_days` decimal(4,1) NOT NULL COMMENT '请假总天数',
  `apply_status` tinyint NOT NULL DEFAULT '1' COMMENT '申请状态：1-待审批 2-已通过 3-已驳回',
  `apply_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '申请时间',
  `approver_id` int DEFAULT NULL COMMENT '审批人ID',
  `remark` varchar(255) DEFAULT NULL COMMENT '请假事由',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`leave_id`),
  KEY `emp_id` (`emp_id`),
  KEY `approver_id` (`approver_id`),
  CONSTRAINT `leave_requests_ibfk_1` FOREIGN KEY (`emp_id`) REFERENCES `employees` (`emp_id`) ON DELETE CASCADE,
  CONSTRAINT `leave_requests_ibfk_2` FOREIGN KEY (`approver_id`) REFERENCES `employees` (`emp_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='请假申请表';
/*!40101 SET character_set_client = @saved_cs_client */;

