--
-- Table structure for table `payroll`
--

DROP TABLE IF EXISTS `payroll`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `payroll` (
  `payroll_id` int NOT NULL AUTO_INCREMENT COMMENT '薪资记录ID',
  `emp_id` int NOT NULL COMMENT '员工ID',
  `salary_month` varchar(7) NOT NULL COMMENT '薪资月份 YYYY-MM',
  `base_salary` decimal(10,2) NOT NULL COMMENT '基本工资',
  `performance_salary` decimal(10,2) DEFAULT '0.00' COMMENT '绩效工资',
  `post_allowance` decimal(10,2) DEFAULT '0.00' COMMENT '岗位补贴',
  `transport_allowance` decimal(10,2) DEFAULT '0.00' COMMENT '交通补贴',
  `meal_allowance` decimal(10,2) DEFAULT '0.00' COMMENT '餐补',
  `other_allowance` decimal(10,2) DEFAULT '0.00' COMMENT '其他补贴',
  `gross_salary` decimal(10,2) NOT NULL COMMENT '应发工资',
  `social_security_personal` decimal(10,2) DEFAULT '0.00' COMMENT '社保个人部分',
  `housing_fund_personal` decimal(10,2) DEFAULT '0.00' COMMENT '公积金个人部分',
  `personal_income_tax` decimal(10,2) DEFAULT '0.00' COMMENT '个人所得税',
  `other_deduction` decimal(10,2) DEFAULT '0.00' COMMENT '其他扣款',
  `net_salary` decimal(10,2) NOT NULL COMMENT '实发工资',
  `pay_status` tinyint DEFAULT '1' COMMENT '发放状态：1-待发放 2-已发放',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`payroll_id`),
  UNIQUE KEY `uk_emp_month` (`emp_id`,`salary_month`),
  CONSTRAINT `payroll_ibfk_1` FOREIGN KEY (`emp_id`) REFERENCES `employees` (`emp_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=37 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='薪酬表';
/*!40101 SET character_set_client = @saved_cs_client */;

