--
-- Table structure for table `recruitment`
--

DROP TABLE IF EXISTS `recruitment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `recruitment` (
  `recruit_id` int NOT NULL AUTO_INCREMENT COMMENT '招聘记录ID',
  `position_name` varchar(64) NOT NULL COMMENT '招聘岗位',
  `position_department` varchar(64) NOT NULL COMMENT '所属部门',
  `candidate_name` varchar(64) NOT NULL COMMENT '候选人姓名',
  `candidate_phone` varchar(20) DEFAULT NULL COMMENT '候选人手机号',
  `candidate_email` varchar(128) DEFAULT NULL COMMENT '候选人邮箱',
  `resume_source` varchar(64) DEFAULT NULL COMMENT '简历来源',
  `resume_parse_status` tinyint DEFAULT '1' COMMENT '解析状态：1-未解析 2-已解析 3-失败',
  `recruit_status` tinyint NOT NULL DEFAULT '1' COMMENT '招聘进度：1-简历筛选 2-初面 3-复面 4-终面 5-Offer 6-已入职 7-淘汰',
  `current_interview_round` tinyint DEFAULT NULL COMMENT '当前面试轮次',
  `interview_time` datetime DEFAULT NULL COMMENT '面试时间',
  `interviewer` varchar(64) DEFAULT NULL COMMENT '面试官',
  `resume_file_path` varchar(255) DEFAULT NULL COMMENT '简历文件路径',
  `education_background` text COMMENT '教育背景 JSON',
  `work_experience` text COMMENT '工作经历 JSON',
  `skill_tags` varchar(255) DEFAULT NULL COMMENT '技能标签',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`recruit_id`)
) ENGINE=InnoDB AUTO_INCREMENT=53 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='招聘候选人表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `recruitment`
--

LOCK TABLES `recruitment` WRITE;
/*!40000 ALTER TABLE `recruitment` DISABLE KEYS */;
